// Giveaway Rules API — รองรับ 3 ระดับ: brand / series / type
const body = ($input.first().json && $input.first().json.body) || $input.first().json || {};
const op = String(body.op || 'list').trim();
const esc = v => (v==null||v==='')?'NULL':"'"+String(v).replace(/'/g,"''")+"'";
const num = v => isFinite(Number(v)) ? Number(v) : 0;
const intOrNull = v => (v==null||v==='')?null:(parseInt(v,10)||null);
const intLit = v => { const i=intOrNull(v); return i===null?'NULL':String(i); };
const d = v => v && /^\d{4}-\d{2}-\d{2}/.test(String(v)) ? `'${String(v).slice(0,10)}'::date` : 'NULL';
let query;

if (op === 'list') {
  const wh = [];
  if (body.status) wh.push(`g.status = ${esc(body.status)}`);
  if (body.brand_id) wh.push(`g.brand_id = ${intOrNull(body.brand_id)}`);
  if (body.series_id) wh.push(`g.series_id = ${intOrNull(body.series_id)}`);
  if (body.type_id) wh.push(`g.type_id = ${intOrNull(body.type_id)}`);
  if (body.part_code) wh.push(`UPPER(g.part_code) LIKE UPPER(${esc('%'+body.part_code+'%')})`);
  const where = wh.length ? ('WHERE ' + wh.join(' AND ')) : '';
  query = `SELECT g.*, b.brand_name, s.series_name, s.marketing_name, m.model_code, t.type_name,
    fmp.product_name AS fmp_product_name,
    CASE WHEN g.type_id IS NOT NULL THEN 'type'
         WHEN g.series_id IS NOT NULL THEN 'series'
         ELSE 'brand' END AS level
    FROM giveaway_rules g
    LEFT JOIN moto_brands b ON b.brand_id = g.brand_id
    LEFT JOIN moto_series s ON s.series_id = g.series_id
    LEFT JOIN moto_types  t ON t.type_id = g.type_id
    LEFT JOIN moto_models m ON m.model_id = t.model_id
    LEFT JOIN LATERAL (
      SELECT MAX(product_name) AS product_name
        FROM honda_inventory
       WHERE REPLACE(UPPER(product_code), '-', '') = REPLACE(UPPER(g.part_code), '-', '')
    ) fmp ON TRUE
    ${where}
    ORDER BY g.status, b.brand_name NULLS LAST, level DESC, s.series_name NULLS LAST, t.type_name NULLS LAST, g.id DESC
    LIMIT 5000;`;
}
else if (op === 'save' || op === 'update') {
  const id = intOrNull(body.id);
  const bid = intOrNull(body.brand_id);
  const sid = intOrNull(body.series_id);
  const tid = intOrNull(body.type_id);
  if (!bid) return [{ json: { query: "SELECT 'missing brand_id' AS message" } }];
  if (!String(body.part_code||'').trim()) return [{ json: { query: "SELECT 'missing part_code' AS message" } }];
  // ถ้าเลือก type ต้องมี series ด้วย (จาก type_id)
  if (id) {
    query = `UPDATE giveaway_rules SET brand_id=${bid}, series_id=${sid===null?'NULL':sid}, type_id=${tid===null?'NULL':tid}, part_code=${esc(body.part_code)}, part_name=${esc(body.part_name)}, qty=${num(body.qty)}, effective_date=${d(body.effective_date)}, end_date=${d(body.end_date)}, note=${esc(body.note)}, status=${esc(body.status||'active')}, updated_at=NOW() WHERE id=${id} RETURNING *;`;
  } else {
    query = `INSERT INTO giveaway_rules (brand_id, series_id, type_id, part_code, part_name, qty, effective_date, end_date, note, status, created_by)
      VALUES (${bid}, ${sid===null?'NULL':sid}, ${tid===null?'NULL':tid}, ${esc(body.part_code)}, ${esc(body.part_name)}, ${num(body.qty)}, ${d(body.effective_date)}, ${d(body.end_date)}, ${esc(body.note)}, ${esc(body.status||'active')}, ${esc(body.created_by)}) RETURNING *;`;
  }
}
else if (op === 'delete') {
  const id = intOrNull(body.id);
  if (!id) return [{ json: { query: "SELECT 'missing id' AS message" } }];
  query = `DELETE FROM giveaway_rules WHERE id=${id} RETURNING id;`;
}
else if (op === 'list_for_type') {
  // ใช้จาก RetailSale: ดึงของแถมที่ใช้กับรถ (type_id เฉพาะ + series + brand) — รวมทั้ง 3 ระดับ
  const tid = intOrNull(body.type_id);
  if (!tid) return [{ json: { query: "SELECT 1 WHERE FALSE" } }];
  query = `WITH vehicle AS (
    SELECT t.type_id, m.series_id, s.brand_id
      FROM moto_types t
      LEFT JOIN moto_models m ON m.model_id = t.model_id
      LEFT JOIN moto_series s ON s.series_id = m.series_id
     WHERE t.type_id = ${tid}
  )
  SELECT g.*,
    fmp.product_name AS fmp_product_name,
    CASE WHEN g.type_id IS NOT NULL THEN 'type'
         WHEN g.series_id IS NOT NULL THEN 'series'
         ELSE 'brand' END AS level
    FROM giveaway_rules g
    CROSS JOIN vehicle v
    LEFT JOIN LATERAL (
      SELECT MAX(product_name) AS product_name
        FROM honda_inventory
       WHERE REPLACE(UPPER(product_code), '-', '') = REPLACE(UPPER(g.part_code), '-', '')
    ) fmp ON TRUE
   WHERE g.status='active'
     AND (g.effective_date IS NULL OR g.effective_date <= CURRENT_DATE)
     AND (g.end_date IS NULL OR g.end_date >= CURRENT_DATE)
     AND (
       (g.type_id = v.type_id)
       OR (g.type_id IS NULL AND g.series_id = v.series_id)
       OR (g.type_id IS NULL AND g.series_id IS NULL AND g.brand_id = v.brand_id)
     )
   ORDER BY level DESC, g.part_code;`;
}
else { query = "SELECT 'unknown op' AS message"; }
return [{ json: { query } }];
